class Solution:
    def shipWithinDays(self, weights: list[int], D: int) -> int:
        lo = max(weights)
        hi = sum(weights)
        while lo < hi:
            mid = (lo + hi) // 2
            days = 1
            cur = 0
            for w in weights:
                if cur + w > mid:
                    days += 1
                    cur = 0
                cur += w
            if days <= D:
                hi = mid
            else:
                lo = mid + 1
        return lo

