#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int shipWithinDays(vector<int>& weights, int D) {
        int lo = *max_element(weights.begin(), weights.end());
        long long hi = 0;
        for (int w : weights) hi += w;
        while (lo < hi) {
            int mid = lo + (hi - lo) / 2;
            int days = 1;
            long long cur = 0;
            for (int w : weights) {
                if (cur + w > mid) {
                    days++;
                    cur = 0;
                }
                cur += w;
            }
            if (days <= D) hi = mid;
            else lo = mid + 1;
        }
        return lo;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> weights(n);
    for (int i = 0; i < n; ++i) cin >> weights[i];
    int D;
    if (!(cin >> D)) return 0;
    Solution sol;
    int ans = sol.shipWithinDays(weights, D);
    cout << ans << "\n";
    return 0;
}
